  ('optician-moex-00177', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用電腦驗光檢查及視網膜鏡驗光檢查的敘述，下列何者正確？', '["電腦驗光檢查是自覺式（subjective）驗光，視網膜鏡驗光檢查是他覺式（objective）驗光", "對於年輕患者，電腦驗光比視網膜鏡驗光會低估遠視度數", "對於年輕患者，電腦驗光比視網膜鏡驗光會低估近視度數", "對於年輕患者，電腦驗光比視網膜鏡驗光會低估散光度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
